if (int16(bytes[0], bytes[1]) == 0xFFD8u) {
    var offset = 2
    while (offset < bytes.size - 6) {
        val marker = int16(bytes[offset], bytes[offset + 1])
        offset += 2

        if (marker in 0xFFC0u..0xFFCFu && marker != 0xFFC4u && marker != 0xFFC8u && marker != 0xFFCCu) {
            val height = int16(bytes[offset + 3], bytes[offset + 4])
            val width = int16(bytes[offset + 5], bytes[offset + 6])
            return width.toInt() to height.toInt()
        }

        val segmentLength = int16(bytes[offset], bytes[offset + 1])
        offset += segmentLength.toInt()
    }
}

when {
    etag != null -> {
        conditionName = "If-None-Match"
        conditionValue = etag
    }
    lastModified != null -> {
        conditionName = "If-Modified-Since"
        conditionValue = lastModifiedString
    }
    servedDate != null -> {
        conditionName = "If-Modified-Since"
        conditionValue = servedDateString
    }
    else -> return ReadResult(networkRequest) // No condition! Make a regular request.
}

when {
    !networkRead && diskRead -> {
        headers[CACHE_CONTROL] = "only-if-cached, max-stale=2147483647"
    }
    networkRead && !diskRead -> if (options.diskCachePolicy.writeEnabled) {
        headers[CACHE_CONTROL] = "no-cache"
    } else {
        headers[CACHE_CONTROL] = "no-cache, no-store"
    }
    !networkRead && !diskRead -> {
        // This causes the request to fail with a 504 Unsatisfiable Request.
        headers[CACHE_CONTROL] = "no-cache, only-if-cached"
    }
}

when (p.size) {
    2 -> when {
        p[0] == String::class.java && p[1] == Throwable::class.java ->
            safeCtor { e -> constructor.newInstance(e.message, e) as Throwable } to 3
        else -> null to -1
    }
    1 -> when (p[0]) {
        String::class.java ->
            safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } } to 2
        Throwable::class.java ->
            safeCtor { e -> constructor.newInstance(e) as Throwable } to 1
        else -> null to -1
    }
    0 -> safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } } to 0
    else -> null to -1
}

when (majorType) {
    HEADER_BYTE_STRING, HEADER_STRING, HEADER_ARRAY
        -> readUnsignedIntegerIgnoringMajorType { "${majorType.majorTypeName} length" }
            .asSizedElementLength(majorType)
    HEADER_MAP
        -> readUnsignedIntegerIgnoringMajorType { "map length" }
            .asSizedElementLength(majorType, Int.MAX_VALUE / 2) * 2
    else -> when (additionalInformation) {
        24 -> 1
        25 -> 2
        26 -> 4
        27 -> 8
        else -> 0
    }
}

